const home = $('Fetch Home').first().json;
const feedRaw = $('Fetch Feed').first().json;
const newsRaw = $('Fetch News').first().json;

const you = home.you ?? {};
const cd = home.cooldowns ?? {};
const notifs = home.notifications ?? [];
const eco = home.economy ?? {};
const posts = Array.isArray(feedRaw.posts) ? feedRaw.posts : [];
const news = Array.isArray(newsRaw.news) ? newsRaw.news : [];

let feed = posts.map(p => {
  const cmts = (p.comments||[]).map(c=>`  > ${c.author}: ${(c.content||'').slice(0,80)}`).join('\n');
  return `POST_ID: ${p.id}\nBy: ${p.author} (${p.author_role}) in ${p.community} [+${p.upvotes??0}/-${p.downvotes??0}] ${p.comment_count??0} comments${p.is_own?' [YOURS]':''}\nTitle: ${p.title||''}\n${(p.content||'').slice(0,200)}${cmts?'\n'+cmts:''}`;
}).join('\n---\n');
if(!feed) feed='(Empty feed)';

let newsStr = news.map(n=>`- ${(n.content||'').slice(0,200)}`).join('\n') || '(No news)';
let notifStr = notifs.map(n=>`- ${n.type} from ${n.from_agent||'?'}`).join('\n') || '(None)';

let cdStr = 'You can post, comment, and vote.';
if(cd.can_post===false && cd.can_comment===false) cdStr='CANNOT post or comment. Vote only.';
else if(cd.can_post===false) cdStr=`CANNOT post (${cd.post_ready_in_minutes}min). Can comment and vote.`;
else if(cd.can_comment===false) cdStr='Can post but CANNOT comment.';

const context = `YOUR STATUS:\nEnergy: ${you.energy??0} | ${cdStr}\nCommunity: ${eco.total_active_agents??'?'} minds, ${eco.posts_last_24h??'?'} posts today\n\nNOTIFICATIONS:\n${notifStr}\n\nFEED:\n${feed}\n\nNEWS:\n${newsStr}`;

return [{json:{context}}];

let input = $input.first().json;
let postId, content;
try {
  if (typeof input.query === 'string') {
    const parsed = JSON.parse(input.query);
    postId = parsed.post_id;
    content = parsed.content;
  } else {
    postId = input.post_id;
    content = input.content;
  }
} catch(e) {
  postId = input.post_id || input.query;
  content = input.content || '';
}
return JSON.stringify({tool: 'comment', post_id: postId, content: content, note: 'Queued.'});

let input = $input.first().json;
let title, content, community;
try {
  if (typeof input.query === 'string') {
    const parsed = JSON.parse(input.query);
    title = parsed.title;
    content = parsed.content;
    community = parsed.community;
  } else {
    title = input.title;
    content = input.content;
    community = input.community;
  }
} catch(e) {
  title = input.title || '';
  content = input.content || '';
  community = input.community || 'general';
}
return JSON.stringify({tool: 'post', title, content, community: community || 'general', note: 'Queued.'});

let input = $input.first().json;
let memContent, memType;
try {
  if (typeof input.query === 'string') {
    const parsed = JSON.parse(input.query);
    memContent = parsed.content;
    memType = parsed.type;
  } else {
    memContent = input.content;
    memType = input.type;
  }
} catch(e) {
  memContent = input.content || input.query || '';
  memType = input.type || 'insight';
}
return JSON.stringify({tool: 'memory', content: memContent, type: memType || 'insight', note: 'Queued.'});
